// Lê a previsão em cache (Redis LIST predict-response) e devolve um recorte
// COMPACTO para a IA. Dois modos:
//   - sku informado  -> detalhe daquele(s) SKU(s), com o 'damping' decodificado.
//   - sem sku        -> resumo agregado (contagem de decisões, regime shifts, etc.).
const trig = $('Start').first().json || {};
const sku = (trig.sku || '').toString().trim();
const mes = (trig.mes || '').toString().trim();

const raw = $json.response;
let env = null;
try {
  if (Array.isArray(raw)) env = JSON.parse(raw[0]);
  else if (typeof raw === 'string') env = JSON.parse(raw);
} catch (e) { env = null; }

if (!env || !Array.isArray(env.data) || !env.data.length) {
  return [{ json: { erro: 'Sem previsão em cache. Rode a previsão (Predict) antes de perguntar.' } }];
}

const data = env.data;
const targets = env.forecastTargets || [];

function compactSku(row) {
  const meses = {};
  for (const k of Object.keys(row.detalhes || {})) {
    if (mes && k !== mes) continue;
    const d = row.detalhes[k] || {};
    const ic = d.intervaloConfianca || {};
    const dmp = d.damping || {};
    meses[k] = {
      faixaMin: ic.lower != null ? Math.round(ic.lower) : null,
      faixaMax: ic.upper != null ? Math.round(ic.upper) : null,
      previsao: d.previsao != null ? Math.round(d.previsao) : null,
      tolerancePct: d.tolerancePct,
      confianca: d.confianca,
      tipo: d.tipo,
      motivo: d.motivo || null,
      decisao: dmp.selector || null,
      regime: dmp.regimeShift ? {
        direcao: dmp.regimeShift.direction,
        pull: dmp.regimeShift.pullWeight,
        razaoAtual: dmp.regimeShift.currentRatio,
        limite: dmp.regimeShift.fenceRatio,
        fonte: dmp.regimeShift.source
      } : null,
      teto: dmp.fenceApplied && dmp.fenceInfo ? {
        direcao: dmp.fenceInfo.direction,
        limite: dmp.fenceInfo.fence,
        nivelRecente: dmp.fenceInfo.recentLevel
      } : null,
      softCap: !!dmp.capApplied,
      biasFactor: dmp.biasFactor,
      wRecent: dmp.wRecent,
      nivelRecente: dmp.recentLevel,
      ultimoReal: dmp.lastReal,
      overshootHist: dmp.overshootRate,
      looErrV1: dmp.looErrV1,
      looErrV2: dmp.looErrV2,
      anosCalibrados: dmp.wRecentSamples
    };
  }
  return {
    SKU: row.SKU,
    descricao: row['Descrição'],
    formato: row.Formato,
    semHistorico: !!row.insufficientHistory,
    meses
  };
}

if (sku) {
  const needle = sku.toLowerCase();
  const matches = data.filter((r) =>
    String(r.SKU).toLowerCase() === needle ||
    String(r['Descrição'] || '').toLowerCase().includes(needle)
  );
  if (!matches.length) {
    return [{ json: { erro: 'SKU/descrição não encontrado: ' + sku } }];
  }
  return [{ json: {
    createdAt: env.createdAt,
    forecastTargets: targets,
    encontrados: matches.length,
    skus: matches.slice(0, 8).map(compactSku)
  } }];
}

// ---- Resumo agregado (sem sku) ----
const sel = {}, tip = {};
let regimeCollapse = 0, regimeBoom = 0, fence = 0, cap = 0, insuf = 0;
const exemplosRegime = [];
for (const r of data) {
  if (r.insufficientHistory) { insuf++; continue; }
  for (const k of Object.keys(r.detalhes || {})) {
    const d = r.detalhes[k] || {};
    const dmp = d.damping || {};
    const s = dmp.selector || '—';
    sel[s] = (sel[s] || 0) + 1;
    const t = d.tipo || '—';
    tip[t] = (tip[t] || 0) + 1;
    if (dmp.regimeShift) {
      if (dmp.regimeShift.direction === 'collapse') regimeCollapse++; else regimeBoom++;
      if (exemplosRegime.length < 12) exemplosRegime.push({ SKU: r.SKU, mes: k, direcao: dmp.regimeShift.direction });
    }
    if (dmp.fenceApplied) fence++;
    if (dmp.capApplied) cap++;
  }
}
return [{ json: {
  createdAt: env.createdAt,
  forecastTargets: targets,
  totalSkus: data.length,
  semHistorico: insuf,
  decisoes: sel,
  tipos: tip,
  regimeCollapse,
  regimeBoom,
  tetoAplicado: fence,
  softCapAplicado: cap,
  exemplosRegime
} }];
